SELECT award_name, award_year
FROM awards
WHERE structure_id = (SELECT structure_id FROM structures WHERE name = 'Tokyo Skytree');

SELECT name 
FROM structures 
WHERE structure_id = 0 AND year BETWEEN 2000 AND 2019;

SELECT name, cost
FROM structures
WHERE cost = (
  SELECT MAX(cost) FROM structures
)
ORDER BY name;

SELECT structure_id
FROM structures
WHERE meters = (
    SELECT MAX(meters) FROM structures
)
LIMIT 1;

SELECT s.name
FROM structures s
WHERE s.meters = (
  SELECT MAX(meters)
  FROM structures
);
